var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"앗, 저기 봐! 아까 그 괴물들이야!","JPN":"あっ、見て！　さっきの怪物たちだわ！","ENG":"Ah, look over there! Those monsters again!","TWN":"啊，妳看那裡！剛才那些怪物是什麼？!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"또 지원군이라고?","JPN":"また援軍だって？","ENG":"More reinforcements?","TWN":"又是援軍嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"이 정도 규모로...... 다이브 해적일 리 없는데...... 그렇다면......","JPN":"この程度の規模なら……ダイブ海賊のはずもないし……ということは……","ENG":"There are way too many of them. They aren't just pirates. They are...","TWN":"這麼大的規模...不可能是躍入的海盜...那這是..."},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"......로스트 쉽 확보 완료.","JPN":"……ロストシップ確保完了。","ENG":"The Lost Ship has been secured.","TWN":"……失落艦船確認完畢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"하지만 미리 숨어들었던 쥐새끼들이 로스트 쉽 내부의 자료를 빼돌렸을 가능성이 있다.","JPN":"しかし、先に潜入したネズミどもが\\nロストシップ内部の資料を持ち出した可能性がある。","ENG":"But the rats that were here before we came might have stolen the data inside the ship.","TWN":"但是內部資料有可能被事先藏在失落艦船裡的鼠輩偷走了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"다이브 라인을 원천 봉쇄하고 전량 회수하도록.","JPN":"ダイブラインをすべて封鎖し、全て回収するように。","ENG":"Close all the Dive lines and collect the data from them.","TWN":"徹底封鎖全部躍入路線，收回所有項目。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"예! 포위망에 갇혔으니 제압은 시간문제입니다!","JPN":"はい！　包囲網を敷いたので、制圧は時間の問題です！","ENG":"Yes, sir! Now that we have them surrounded, it's only a matter of time before we catch them.","TWN":"是！只要他們被困在我們的包圍圈裡，制服他們就只是時間的問題了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"제나! 지시를 부탁해!","JPN":"ジーナ！　指示をお願い！","ENG":"Zena, just tell us what to do.","TWN":"珍娜，請指示!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"우리가 최선을 다해 볼게!","JPN":"二人で頑張ってみるから！","ENG":"We'll do our best to do it.","TWN":"我們會全力以赴！!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"하, 하지만...... 난 이런 상황은 처음이라서......","JPN":"で、でも……私はこんな状況が初めてで……","ENG":"B-but... I've never been in a situation like this before...","TWN":"但、但是...我還是第一次碰上這種情況呢……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"가뜩이나 열세인데, 사방으로 둘러싸였을 때의 대처법 같은 건...... 난......","JPN":"ただでさえ劣勢なのに、包囲された時の対処法なんて……私は……","ENG":"We're outnumbered, and surrounded by enemies everywhere. I don't... I...","TWN":"本來就處於劣勢，並且在四面都被包圍的應對方法是…是……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"제나, 교육생 시절에 배웠던 건 더 이상 떠올리지 말아요.","JPN":"ジーナ、教育生時代に習ったことは思い出さなくても大丈夫ですよ。","ENG":"Zena, don't think about what you've learned as a trainee.","TWN":"珍娜，妳不要再去想學校裡教的那些SOP之類的東西了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"......응?","JPN":"……え？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"우린 관리국 직할 카운터고, 상대는 침식체와 다를 바 없는 괴물이에요.","JPN":"私たちは管理局の直轄カウンターで、相手は侵食体も同然の怪物です。","ENG":"We're the Administration's official Counters, and they're monsters no better than C.O.","TWN":"我們是管理局直轄的制裁者，並且對手是與侵蝕體無異的怪物們。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"침식체에 포위되었을 때, 어떻게 해야 하는지는 간단하잖아요?","JPN":"侵食体に囲まれた時、どうすればいいかなんて簡単でしょう？","ENG":"You know what to do when you're surrounded by C.O.'s, right?","TWN":"所以當我們被侵蝕體包圍時，要怎麼做不是很簡單嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"침식체...... 카운터......","JPN":"侵食体……カウンター……","ENG":"Corrupted Objects... Counters...","TWN":"侵蝕體...制裁者..."},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"그래. 우린 오피셜 서포트.","JPN":"そう。私たちはオフィシャルサポート。","ENG":"Yes. We're the Official Support.","TWN":"對啊，我們是官方支援小隊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"모범이 되어야 할 우리가, 침식체 상대로 겁에 질려서 손 놓고 있을 수는 없어......!","JPN":"模範になるべき私たちが、侵食体を相手に怖気づいていてはいけない……！","ENG":"We can't let some C.O.'s terrorize us. We're exemplary Counters.","TWN":"我們得做出榜樣，面對侵蝕體，我們不能因害怕就束手無策……!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"아이리, 캐시! 어떻게든 새로운 돌파구를 만들어 보자!","JPN":"アイリ、キャシー！　何とか新しい突破口を作ってみよう！","ENG":"Irie, Cathy! Let's cut a path through them at all costs.","TWN":"珍娜、凱西！無論如何我們都要找到新的突破口！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"좋아요. 마지막까지 최선을 다해 보죠.","JPN":"ええ！　最後までベストを尽くしますよ。","ENG":"Yes. Let's do our best until the end.","TWN":"好，讓我們拚盡全力直到最後。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"앗! 캐시 치사해! 아이리 님도 멋진 멘트 생각 중이었는데!","JPN":"あっ！　キャシーずるい！　アイリ様もカッコいい一言を考えてたのに！","ENG":"Ah! Cathy, you stole my thunder! Irie was also thinking about a great thing to say!","TWN":"啊！凱西妳好卑鄙！艾莉也想要說帥氣的台詞耶!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"지휘관님, 쥐새끼들이 머리를 내밀었습니다!","JPN":"指揮官様、ネズミどもが姿を現しました！","ENG":"Commander, the rats have come out of their hidey-hole!","TWN":"指揮官大人，老鼠們探出頭來了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"투항할 기색은 없군. 귀찮게 처형할 수고는 덜겠어.","JPN":"投降する気配はないな。\\nわざわざ手順を踏んで処刑する手間は省けそうだ。","ENG":"They don't look like they want to surrender. We don't have to waste our time executing them, then.","TWN":"不過她們沒有投降的意思，處刑得花上不少時間呢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"허약해도 카운터는 카운터. 융합체의 전투 데이터 수집 대상으로 쓸 만하겠지.","JPN":"弱くてもカウンターはカウンターだ。融合体の戦闘データ収集に使えるだろう。","ENG":"Counters are Counters, no matter how weak. We can use them to collect combat data for Hybriders.","TWN":"就算再怎麼弱，制裁者還是制裁者。作為融合體戰鬥資料的收集對象也還過得去吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"전원, 전투 태세를 갖춰라!","JPN":"全員、戦闘態勢を整えろ！","ENG":"Everyone, get ready to fight!","TWN":"全員準備戰鬥！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"측면에서 폭발이......?! 무슨 일이냐!","JPN":"側面から爆発が……！？　何事だ！","ENG":"What was that explosion from the side? What happened?","TWN":"側面發生爆炸…!? 怎麼回事？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"봉쇄가 뚫렸습니다! 태스크포스 강습함입니다!","JPN":"封鎖が破られました！　タスクフォースの強襲艦です！","ENG":"Our siege has been broken. By a TASKFORCE assault ship!","TWN":"我方封鎖線被突破了！是特遣強襲戰艦！？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"당신들이 오피셜 서포트인가?","JPN":"君たちがオフィシャルサポートか？","ENG":"Are you the Official Support?","TWN":"妳們是支援小隊嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"늦지 않았을까 걱정했는데, 다행히 아직 무사한가 보군.","JPN":"遅かったかと心配したが、幸い無事なようだな。","ENG":"I'm glad I'm not too late.","TWN":"我還在擔心會不會來晚了，幸好妳們全都平安無事。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"당신은......?","JPN":"あなたは……？","ENG":"You?","TWN":"你們是…？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"내 이름은 에스테로사 드 슈발리에.","JPN":"私の名はエステロサ・ド・シュヴァリエ。","ENG":"My name is Esterosa de Chevalier.","TWN":"我是：艾斯特洛索。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠 블루시프트의 단장이다.","JPN":"ゾディアックナイツ：ブルーシフトの団長だ。","ENG":"I'm the captain of the Zodiac Knights: Blue Shift.","TWN":"是「十二宮騎士團：藍移」的團長。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"관리국의 긴급 작전 의뢰를 받아 그대들을 구출하러 왔다.","JPN":"管理局より緊急作戦の依頼を受けて、君たちを救出しに来た。","ENG":"I came to rescue you at the urgent request of the Administration.","TWN":"受管理局緊急作戰委託，我方來營救你們。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"조디악 나이츠? 그 기사단 컨셉 활동으로 유명한......?","JPN":"ゾディアックナイツ？　あの騎士団ごっこで有名な……？","ENG":"The Zodiac Knights? Oh, the group famous for its knight theme!","TWN":"十二宮騎士團：藍移？是廣告中很有名的那個「騎士團」嗎…？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"컨셉이라니요. 우린 세계를 침식해오는 이면세계의 위협에 맞서 인류를 수호하는 기사들입니다.","JPN":"単なるコンセプトではありませんよ。\\n私たちは、世界を侵食する裏世界の脅威に立ち向かって、人類を守護する騎士なんです。","ENG":"It's not a theme. We really are knights who protect mankind against the encroaching threat of the Counterside.","TWN":"什麼廣告...我們可是面對侵蝕世界的異界威脅，守護全人類的騎士耶！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"우와~♪ 진짜 기사 같아! 멋지다~♪","JPN":"うわぁ～♪　本物の騎士みたい！　カッコいい～♪","ENG":"Whoa! ♪ You really look like knights! So cool! ♪","TWN":"嗚哇~♪ 連語氣都跟報導的一樣，太帥了！~♪"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"흠, 그래도 식견 높은 분이 계시는군요.","JPN":"ふむ、見る目のある方がいらっしゃいますね。","ENG":"Hmm, at least one of you is insightful.","TWN":"嗯，看來這裡還是有眼光不錯的人的嘛~"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"당신의 그 반응을 높이 사서, 이 자리를 빌어 한 가지 가르쳐 드리겠습니다.","JPN":"あなたに敬意を払い、この場を借りて一つお教えしましょう。","ENG":"Because I appreciate your response, I'll share something with you.","TWN":"妳的反應我很滿意，所以我就藉這個機會教妳一件事吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"응? 뭘 말이야? 재밌는 거야?","JPN":"うん？　何を教えてくれるの？　面白いもの？","ENG":"Mm? Like what? Is it interesting?","TWN":"嗯？是什麼？很有趣嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"자고로 많은 사람들이 상상하는 진짜 기사란 어디까지나 기사도 문학의 산물입니다.","JPN":"多くの方が想像する本物の騎士とは、あくまでも騎士道文学の産物です。","ENG":"The knight that most people picture in their heads is the pure product of chivalric romance.","TWN":"自古以來，人們想像中的騎士始終是文學的產物。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"물론 저희 열두 가문의 기사도도 사람들이 그려낸 이상적인 이미지에 많은 영향을 받아 왔겠죠.","JPN":"もちろん私たち十二名家の騎士道も、\\n人々が思い描いた理想像に大きな影響を受けてきたでしょう。","ENG":"And I have no doubt that in many ways it has influenced us, the twelve houses of the Knights.","TWN":"當然也因為如此，關於我們十二宮騎士團的報導，一定程度上也受到了人們理想色彩所影響了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 선조님들께서는 조디악 나이츠의 숭고한 결성 의지가 피상적인 규범 뒤에 가려지는 것을 경계하셨습니다.","JPN":"しかし、私たちの先祖はゾディアックナイツの崇高な結成意志が\\n皮相的な規範に隠れてしまうことを危惧しました。","ENG":"But our ancestors didn't want the noble intentions of the Zodiac Knights to be overshadowed by such superficial standards.","TWN":"但祖先們仍對十二宮騎士團的崇高意志保持著一顆尊敬的心。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"특히 저희 로웰 가문에서는 기사단의 신념을 올바르게 계승하기 위해......","JPN":"特に我がローウェル家では、騎士団の信念を正しく継承するために……","ENG":"Especially, the members of my family, Lowell, in order to uphold the convictions of the Knights—","TWN":"特別是我們的勞威爾家族，為了能夠繼承正統的騎士團信念，我們……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"미안~ 듣고 있으니까 눈이 핑핑 돌아~","JPN":"ごめ～ん、聞いてたら目が回りそうだわ～。","ENG":"Sorry, but I can't listen to you anymore. You're making me feel dizzy.","TWN":"對不起~我頭有點暈~"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"부단장, 소개는 이쯤 하지.","JPN":"副団長、紹介はその程度にしよう。","ENG":"Deputy Captain, maybe that's enough for our introduction.","TWN":"副團長，介紹就到此為止吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"크흠. 흠...... 죄송합니다.","JPN":"こほん。ふむ……失礼しました。","ENG":"Hmpf! *Ahem* I'm sorry.","TWN":"咳、咳咳....不好意思！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"그런데 저희가 여기 있다는 건 어떻게 알고 오셨어요?","JPN":"ところで、私たちがここにいることをどうやって知ったんですか？","ENG":"By the way, how did you know we were here?","TWN":"但你們是怎麼知道我們在這裡的?"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"이런 말을 하긴 그렇지만, 저희가 온 건 관리국에 보고된 사안이 아니거든요.","JPN":"ちょっと言いにくいのですが、\\n私たちは管理局に報告された事案で来たわけではないのです。","ENG":"Truth be told, the Administration shouldn't have known that we're here.","TWN":"雖然這件事難以啟齒，但我們來到此處的事情並沒有向管理局報告過。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"자세한 사정은 듣지 못했다.","JPN":"詳しい事情はまだ聞いていない。","ENG":"I wasn't provided with the details.","TWN":"我們也不瞭解詳情。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"관리국의 대리자에게 다이브 중 위험에 처한 사람들을 구해 달란 의뢰를 받았을 뿐.","JPN":"管理局の代理者から、ダイブ中に危険にさらされた人々を助けてほしいと依頼されただけだ。","ENG":"I was only asked by an agent of the Administration to save some distressed Divers.","TWN":"我們只是收到管理局的代理委託，要我們去救助在躍入中陷入危險之中的人，僅此而已。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"겨우 그런 정보만 가지고 이런 위험한 곳까지 다이브를 하다니, 이유가 고작 그것뿐이라고요? 정말로?","JPN":"たったそれだけの情報でこんな危険な所にダイブするなんて……\\n本当に理由はそれだけですか？　本当に？","ENG":"You dived into this dangerous place just to save some people you don't know nothing about? Are you serious?","TWN":"光憑這些情報就躍入到這麼危險的地方，而且理由就只有這些？真的嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"비용문제를 넘어서 보통 위험한 일이 아니란 것쯤은 아실 텐데...... 허탕이라도 치면 어쩌려고요?","JPN":"費用の問題だけでなく、相当危険だってことくらい予想できただろうし……\\n徒労に終わる可能性もあるでしょう？","ENG":"Never mind the expense. You could have died coming here. And what if you didn't find us?","TWN":"先不管花費的問題，但這件事可不是一般的危險程度…如果到頭來你們是白費力氣怎麼辦呢？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"허탕이라는 말은 적절하지 않군.","JPN":"徒労という言葉は適切じゃないな。","ENG":"Perhaps you don't know who we are.","TWN":"白費力氣這個詞並不貼切。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"부단장, 조디악 나이츠의 제 1 사명이 뭔지 읊어 보겠나?","JPN":"副団長、ゾディアックナイツの最大の使命が何か、言ってもらえるか？","ENG":"Deputy Captain, why don't you recite the First Mission of the Zodiac Knights?","TWN":"副團長，能勞煩妳朗誦一下十二宮騎士團的第一使命是什麼嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠의 제 1사명은 언제나 위험에 처한 사람들을 구하는 것입니다.","JPN":"ゾディアックナイツの最大の使命は、いついかなる時も危険にさらされた人々を救うことです。","ENG":"The First Mission of the Zodiac Knights is to save people in danger, no matter what.","TWN":"十二宮騎士團的第一使命——拯救身陷危險之中的人們。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"사람을 구하는 일에는 손익을 저울질할 필요가 없다는 뜻이죠.","JPN":"人々を救うことに損得勘定は不要、という意味です。","ENG":"In other words, we put saving lives before everything else, even our own lives.","TWN":"也就是救人不必計較得失的意思。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"우와~♪ 터무니없지만 멋져!","JPN":"うわぁ～♪　めちゃくちゃだけど素敵！","ENG":"Wow! ♪ That sounds so ridiculous, but so cool!","TWN":"嗚哇~♪雖然聽起來很荒唐但帥斃了!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"아무래도...... 여러분은 소문과는 많이 다른 것 같네요.","JPN":"どうやら……皆さんは噂とは違うようですね。","ENG":"You're not at all like what I've heard you are.","TWN":"也許…你們和傳聞中說的不一樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"아이리.","JPN":"アイリ。","ENG":"Irie.","TWN":"艾莉。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"What?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"저 얼굴, 어디서 본 것 같지 않아?","JPN":"あの顔、どこかで見たことないか？","ENG":"Doesn't she look familiar to you?","TWN":"這張臉...好像在哪裡見過似的？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"......앗! 그러고 보니 선도부장이잖아!","JPN":"……あっ！　そうね、風紀委員長だわ！","ENG":"... Ah! The Student Guide Leader!","TWN":"……啊！現在一看，這不是先鋒部隊長嘛！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"음? 선도부장?","JPN":"ん？　風紀委員長？","ENG":"Hmm? What Leader?","TWN":"嗯？？先鋒部隊長？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"기사단장님, 혹시 아이리 님이랑 만난 적 있어?","JPN":"騎士団長、ひょっとしてアイリ様に会ったことある？","ENG":"Knight Captain, have you met Irie before?","TWN":"騎士團長大人，想請問…或許您有曾經見過艾莉的印象嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"......글쎄.","JPN":"……さあ。","ENG":"I doubt it.","TWN":"……這個嘛。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"미안하군. 사람 얼굴이라면 제법 잘 기억한다고 자부하고 있지만......","JPN":"すまないな。人の顔を覚えることには自信があるほうだが……","ENG":"I'm sorry. I'm pretty good at remembering people's faces,","TWN":"抱歉，要記住一個人的臉我是很有自信的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"자네 얼굴은 내 기억에 없다. 선도부장이라고 해도 무슨 뜻인지 모르겠군.","JPN":"君の顔は記憶にないな。風紀委員長と言われても何のことかわからない。","ENG":"but you're not in my memory. I don't know what you meant by Student Guide Leader, either.","TWN":"但我對妳的臉沒有印象，而且妳們說的先鋒部隊長，我也不知道是什麼意思。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"기대했던 대답을 주지 못해 미안하다.","JPN":"期待どおりの返事ができなくてすまない。","ENG":"I'm sorry I can't give you the answer you want.","TWN":"沒能回應妳的期待我很抱歉。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"으응, 아냐. 아이리님이 더 미안♪ 다른 사람이랑 착각했나 봐♪","JPN":"ううん、いいわ。アイリ様こそごめんね♪　他の人と勘違いしたみたい♪","ENG":"Oh, no worries. Irie's sorry. ♪ She's mistaken you for someone else. ♪","TWN":"嗯~~不會，艾莉才更抱歉呢♪ 把妳錯認成別人了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"잡담이 길어졌군. 우선 급한 불부터 진화하도록 하지.","JPN":"無駄話が長くなったな。まずは急ぎの問題から解決しよう。","ENG":"Enough chitchat. Let's take care of the matter at hand first.","TWN":"我們閒聊太久了，先處理緊急的事情吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스 경, 한솔 견습. 언제나처럼 뒤를 부탁한다.","JPN":"アリウス、ヤガミ。いつものように後方を頼む。","ENG":"Dame Arius. Page Hansol. I trust you to have our backs.","TWN":"埃里奧斯卿，楊瀚見習團員，你們的任務和往常一樣，後方就交給你們了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"네, 단장님. 지원은 맡겨 주세요.","JPN":"はい、団長。支援ならお任せください。","ENG":"Yes, Captain. Count on us for the support you need.","TWN":"是，團長！支援的任務就交給我吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"견습단원 양한솔! 최선을 다하겠습니다!","JPN":"見習い団員、ヤガミ・イチロウ！　全力でやります！","ENG":"Page Hansol will do his best to serve you, ma'am!","TWN":"見習團員楊瀚，一定會全力以赴的!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"부단장과 리브 경은 나와 함께 전면에 선다!","JPN":"副団長とリブは、私と一緒に前方を！","ENG":"Deputy Captain and Dame Liv, you'll fight on the front line alongside me.","TWN":"副團長和莉芙卿，你們和我一起上前線!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"제 창은 언제든 준비되어 있습니다, 단장님.","JPN":"私の槍はいつも準備万全です、団長。","ENG":"My spear is always ready, Captain.","TWN":"我們隨時為妳效命，團長。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"저 줄을 무너뜨리면 되는 거지? 맡겨 두라구!","JPN":"あの列を崩せばいいんだよね？　任せといて！","ENG":"You want to disrupt that line, right? You got it, Captain!","TWN":"要擊潰他們的戰線嗎？交給我吧!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"좋아. 관리국의 정보에 따르면, 적은 테러리스트 단체인 리플레이서 신디케이트다.","JPN":"よし。管理局の情報によると、敵はテロリスト集団のリプレイサー・シンジケートだ。","ENG":"Good. According to the Administration, we're dealing with a terrorist group called the Replacer Syndicate.","TWN":"很好！根據管理局的情報，敵人是恐怖組織“克隆集團”。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"인간을 제물로 삼는 명실상부한 악인들이니 사정 봐주지 말고 철저하게 응징하도록.","JPN":"人間を生贄にする正真正銘の悪党だ。情け容赦なく徹底して戒めるように。","ENG":"These villains prey on innocent people. Don't show them mercy.","TWN":"那些把人類當作犧牲品，名符其實的惡棍，所以不需要手下留情，徹底嚴懲他們！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"돌격!!","JPN":"突撃！！","ENG":"Charge!","TWN":"突擊!!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"이게 그 로스트 쉽에서 찾아온 메모리 뱅크로군.","JPN":"これがあのロストシップで見つけてきたメモリーバンクだな。","ENG":"This is a memory bank you've found in the Lost Ship.","TWN":"這就是從那艘失落艦船上找到的資料記憶體啊。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"교섭은 잘 되었나? 그냥 달라고 하면 반발이 꽤 심했을 텐데.","JPN":"交渉は上手くいったか？　見返りもなく要求したら反発も激しかっただろう。","ENG":"How did you make them give it up? They wouldn't have let it go without a fight.","TWN":"交涉還順利嗎？如果直接提出要求，肯定會遭到強烈反抗的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 관리국 내부 정보를 빼돌려서 시도한 무단도굴이었으니까요.","JPN":"そもそも、管理局の情報を盗み出して試みた無断盗掘でしたからね。","ENG":"They found it based on an internal tip that they stole from the Administration.","TWN":"說到底，這本來就是她們擅自竊取了管理局的內部情報。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"목숨을 구하고 라이선스까지 온존하게 되었는데, 불만을 품는다면 상도덕이 없다고 해도 되겠죠.","JPN":"命も助かってライセンスまで守れたのに、不満を抱くなんてもってのほかでしょう。","ENG":"We let them live and keep their license. It would have been extremely ungrateful of them if they'd protested.","TWN":"現在她們撿了條命，連許可證都保住了，如果還有什麼不滿的話，這也太沒有道德了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관리국에서는 이번 일로 오피셜 서포트에 대한 홀대 분위기를 개선할 방침이라고 합니다.","JPN":"管理局は今回の件を機に、オフィシャルサポートに対する冷遇を改善する方針だそうです。","ENG":"Also, the Administration will improve its treatment of the Official Support.","TWN":"管理局說經過這次事件，他們會改善官方支援小隊的待遇。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하긴 그렇지. 명색이 관리국 직할인데 바나나 살 돈도 없어서야 되겠나.","JPN":"確かにそうだな。仮にも管理局直轄なのにバナナを買う金もないのは話にならない。","ENG":"It should. They're directly under the Administration's management, and yet they don't even have money to buy bananas.","TWN":"本來就該如此，明明也是管理局的直屬單位，怎麼會連買香蕉的錢都沒有呢？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자료 압수 건은 불법 도굴 기록 말소를 통해 애초에 없던 일로 하는 식으로 원만하게 해결됐습니다.","JPN":"資料押収の件は不法盗掘記録を抹消し、\\n最初からなかったことにする方向で円満に解決しました。","ENG":"Their illegal excavation record will be wiped out, too, in exchange for the data.","TWN":"就沒收資料以及這案子就用幫她們抹消非法盜掘記錄來交換，事情已經圓滿地解決了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래. 수고 많았네.","JPN":"ああ。ご苦労だった。","ENG":"I see. Good job.","TWN":"是啊，真是辛苦了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"음? 뭔가 할 말이라도 있나?","JPN":"何だ？　言いたいことでもあるのか？","ENG":"Mm? Is there anything else you want to say?","TWN":"嗯？妳還想要說什麼嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 데이터 뱅크에 들어 있는 자료 말입니다만......","JPN":"そのデータバンクに入っている資料ですが……","ENG":"About the data in the data bank.","TWN":"雖說是那個資料庫裡的檔案，但..."},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 왜 그걸 입수하려고 하신 거죠?","JPN":"それを手に入れようとした理由は何ですか？","ENG":"Why did you want them?","TWN":"為什麼我們一定要把它弄到手啊?"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관리국 행정관 대신 저를 통해서 비밀리에 협상하신 걸 보면, 뭔가 알려져서는 안 될 내용이라도 되는 건가요?","JPN":"管理局の行政官ではなく私に交渉させたのは、\\n何か知られてはいけない内容でもあるからですか？","ENG":"You sent me instead of an Administration official to negotiate with them in private. Do they contain information that must be revealed?","TWN":"不是通過管理局的行政官，而是通過我來進行秘密協商，從這角度來看，那難道是一個不能公開的內容嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"글쎄......","JPN":"そうだな……","ENG":"Well...","TWN":"這個嘛…"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"자네는 그걸 보면서 무슨 감상이 들었나?","JPN":"君はこれを見ながら何を感じた？","ENG":"What did you think when you watched the videos?","TWN":"妳在看這些內容的時候有什麼感想？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"내가 아는 자네라면 보고 전에 허락 없이 미리 확인해 봤을 거라고 생각하는데.","JPN":"私が知っている君なら、報告する前に許可もなく確認しただろう。","ENG":"The Sooyeon I know would already have watched them.","TWN":"以我對妳的瞭解，就算沒有許可妳也會在事前先確認內容。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그야 물론입니다만...... 내용을 보고 나니 더 혼란스럽군요.","JPN":"もちろんそうですが……内容を見たら混乱しました。","ENG":"I did, of course. They only made me feel more confused than ever.","TWN":"那當然了……但看了內容後,我反而更加混亂。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 영상들은...... 분명 당신의 비밀을 푸는 데는 흥미로운 자료들이었습니다.","JPN":"その映像は……確かにあなたの秘密を解く鍵になる、興味深い資料でした。","ENG":"Those videos... They definitely have clues to your secrets.","TWN":"那些影像....一定能夠解開你的秘密，是份耐人尋味的資料。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"결손된 기억을 되찾는 데 유용하게 쓰일지도 모르지만...... 이렇게 무리할 만큼 전략적 가치가 있다고는 생각되지 않습니다.","JPN":"欠けた記憶を取り戻すには有用かもしれませんが……\\nここまで無理をするほど戦略的な価値があるものとは思えません。","ENG":"They may be helpful to retrieving your memories, but I don't think they're strategically valuable enough to spend so much effort.","TWN":"而且對於找回喪失的記憶或許也很有用...但我不認為它有讓我們這麼拼命的戰略價值。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"잘 봤네.","JPN":"そのとおりだ。","ENG":"You're right.","TWN":"說得好。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"이건 그냥...... 옛 추억이 담긴 앨범 같은 거지.","JPN":"これはただ……昔の思い出が詰まったアルバムのようなものだ。","ENG":"This bank... It's just like an old album.","TWN":"它看起來…就像是一本充滿回憶的相簿。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"왜 그런 경험 없나?","JPN":"そんな経験はないか？","ENG":"Haven't you ever had an experience like that?","TWN":"妳沒有那種經驗嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"오랫동안 있는지도 모를 만큼 잊고 지내다가, 우연히 눈에 띄면 펼쳐 보지 않고 못 배기는 추억의 앨범 말일세.","JPN":"長い間、存在することすら忘れていたのに、\\n偶然目についた思い出のアルバムを開かずにはいられなかった経験だよ。","ENG":"You find an old album that you completely forgot about. The moment you open it, all the good memories from your old days flood back to you.","TWN":"像是一本曾忘記了很久，偶然被發現就很自然地翻閱的…充滿各種回憶的相簿。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전 앨범 같은 걸 만들어본 적이 없습니다.","JPN":"私はアルバムなんて作ったことありません。","ENG":"I've never made any albums.","TWN":"我沒有做過相簿之類的東西，抱歉。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그거 유감이군.","JPN":"それは残念だ。","ENG":"That's a shame.","TWN":"那還真是遺憾。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"어쨌든 내 개인적인 일이라고 생각해 주면 고맙겠어.","JPN":"とにかく、私の個人的な件だと理解してくれるとありがたい。","ENG":"Anyway, just think of this as my personal project.","TWN":"但不管怎麼說，我很感謝妳願意認為這是一件關於我個人的事情。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......알겠습니다. 그런 걸로 해 두죠.","JPN":"……わかりました。そういうことにしましょう。","ENG":"Understood. I'll do that.","TWN":"…我知道了，那就這麼做吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이번 일에 대한 대가는 빚으로 달아두도록 하겠습니다.","JPN":"今回の件の対価は、ツケにしておきますからね。","ENG":"You owe me for this.","TWN":"這次的工作我會記在帳上，"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다음에 관리국에 아쉬운 소리를 할 일이 생기면 그때 정산하는 걸로 하죠.","JPN":"また管理局に頭を下げるようなことがあれば、その時精算することにしましょうか。","ENG":"I'll call in this marker later when I need something for leverage with the Administration.","TWN":"下次萬一我有什麼要跟管理局說的，我就會來算算這筆帳。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"......그래, 잘 달아 두게나.","JPN":"……ああ、そうしてくれ。","ENG":"Sure, better not forget that.","TWN":"……不錯，很會精打細算。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};